6	  <title>{{userName}}</title>
7	  <style>
8	    :root {
9	      --bg: #09090b;
10	      --surface: #131316;
11	      --text: #ededf0;
12	      --muted: #8b8b96;
13	      --accent: #5eead4;
14	      --accent-2: #a78bfa;
15	      --border: #232329;
16	    }
17	
18	    * {
19	      margin: 0;
20	      padding: 0;
21	      box-sizing: border-box;
22	    }
23	
24	    html {
25	      scroll-behavior: smooth;
26	    }
27	
28	    ::selection {
29	      background: rgba(94, 234, 212, 0.25);
30	    }
31	
32	    body {
33	      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
34	      background: var(--bg);
35	      color: var(--text);
36	      line-height: 1.6;
37	      -webkit-font-smoothing: antialiased;
38	    }
39	
40	    .container {
41	      max-width: 720px;
42	      margin: 0 auto;
43	      padding: 0 24px;
44	    }
45	
46	    /* Header / hero */
47	    header {
48	      position: relative;
49	      padding: 96px 0 64px;
50	    }
51	
52	    header::before {
53	      content: "";
54	      position: absolute;
55	      top: -160px;
56	      left: -120px;
57	      width: 480px;
58	      height: 480px;
59	      background: radial-gradient(circle, rgba(94, 234, 212, 0.08), transparent 70%);
60	      pointer-events: none;
61	    }
62	
63	    .avatar {
64	      width: 88px;
65	      height: 88px;
66	      border-radius: 50%;
67	      background: linear-gradient(135deg, var(--accent), var(--accent-2));
68	      display: flex;
69	      align-items: center;
70	      justify-content: center;
71	      font-size: 32px;
72	      font-weight: 700;
73	      color: var(--bg);
74	      margin-bottom: 24px;
75	      box-shadow: 0 0 40px rgba(94, 234, 212, 0.25);
76	    }
77	
78	    h1 {
79	      font-size: 40px;
80	      font-weight: 700;
81	      letter-spacing: -0.02em;
82	      margin-bottom: 8px;
83	    }
84	
85	    .tagline {
86	      font-size: 20px;
87	      color: var(--muted);
88	      margin-bottom: 24px;
89	    }
90	
91	    .intro {
92	      font-size: 17px;
93	      color: var(--text);
94	      max-width: 60ch;
95	    }
96	
97	    /* Sections */
98	    section {
99	      padding: 40px 0;
100	      border-top: 1px solid var(--border);
101	    }
102	
103	    h2 {
104	      font-size: 14px;
105	      font-weight: 600;
106	      text-transform: uppercase;
107	      letter-spacing: 0.08em;
108	      color: var(--muted);
109	      margin-bottom: 24px;
110	    }
111	
112	    /* Work / projects */
113	    .card {
114	      display: block;
115	      background: var(--surface);
116	      border: 1px solid var(--border);
117	      border-radius: 12px;
118	      padding: 20px 24px;
119	      margin-bottom: 16px;
120	      text-decoration: none;
121	      color: inherit;
122	      transition: border-color 0.15s ease, transform 0.15s ease;
123	    }
124	
125	    .card:hover {
126	      border-color: var(--accent);
127	      transform: translateY(-2px);
128	      box-shadow: 0 4px 24px rgba(94, 234, 212, 0.1);
129	    }
130	
131	    .card h3 {
132	      font-size: 17px;
133	      font-weight: 600;
134	      margin-bottom: 4px;
135	    }
136	
137	    .card p {
138	      font-size: 15px;
139	      color: var(--muted);
140	    }
141	
142	    /* Contact links */
143	    .links {
144	      display: flex;
145	      flex-wrap: wrap;
146	      gap: 12px;
147	    }
148	
149	    .links a {
150	      display: inline-block;
151	      padding: 10px 18px;
152	      border: 1px solid var(--border);
153	      border-radius: 999px;
154	      color: var(--text);
155	      text-decoration: none;
156	      font-size: 15px;
157	      transition: border-color 0.15s ease, color 0.15s ease;
158	    }
159	
160	    .links a:hover {
161	      border-color: var(--accent);
162	      color: var(--accent);
163	    }
164	
165	    footer {
166	      padding: 40px 0 64px;
167	      border-top: 1px solid var(--border);
168	      color: var(--muted);
169	      font-size: 14px;
170	    }
171	
172	    @media (max-width: 480px) {
173	      header {
174	        padding: 64px 0 48px;
175	      }
176	
177	      h1 {
178	        font-size: 32px;
179	      }
180	
181	      .tagline {
182	        font-size: 18px;
183	      }
184	    }
185	  </style>
186	</head>
187	<body>
188	  <div class="container">
189	    <header>
190	      <div class="avatar">AK</div>
191	      <h1>{{userName}}</h1>
192	      <p class="tagline">Software engineer &amp; builder</p>
193	      <p class="intro">
194	        Hi, I'm {{userName}}. I build software and enjoy turning ideas into simple,
195	        well-crafted tools. This is my corner of the internet — a place for
196	        what I'm working on and how to reach me.
197	      </p>
198	    </header>
199	
200	    <section>
201	      <h2>What I'm working on</h2>
202	      <a class="card" href="#">
203	        <h3>Project One</h3>
204	        <p>A short description of what this project does and why it exists.</p>
205	      </a>
206	      <a class="card" href="#">
207	        <h3>Project Two</h3>
208	        <p>Another thing I've built or am currently exploring.</p>
209	      </a>
210	    </section>
211	
212	    <section>
213	      <h2>Get in touch</h2>
214	      <div class="links">
215	        <a href="mailto:<email>">Email</a>
216	        <a href="https://github.com/" target="_blank" rel="noopener">GitHub</a>
217	        <a href="https://www.linkedin.com/" target="_blank" rel="noopener">LinkedIn</a>
218	      </div>
219	    </section>
220	
221	    <footer>
222	      &copy; 2026 {{userName}}
223	    </footer>
224	  </div>
225	</body>
226	</html>
